class TestBitmask:
    """Test bitmask serialization."""

    def test_bitmask_creation_and_access(self):
        """Test basic bitmask operations."""
        mask = EncoderBitmask(0, 1024, [10, 50, 100, 512])
        assert mask.num_frozen() == 4
        assert mask.pct_frozen() == 4 / 1024 * 100
        assert mask.estimated_speedup() > 1.0

    def test_bitmask_serialization_roundtrip(self):
        """Test serialization and deserialization."""
        original = EncoderBitmask(5, 8192, list(range(0, 1000, 10)))
        blob = original.to_bytes()

        # Deserialize
        restored = DecoderBitmask.from_bytes(5, 8192, blob)
        assert restored.num_frozen() == original.num_frozen()
        assert restored.pct_frozen() == original.pct_frozen()

        # Verify all indices are correct
        for idx in original.frozen_indices:
            assert restored.is_frozen(idx)

    def test_empty_bitmask(self):
        """Test empty bitmask."""
        mask = EncoderBitmask(0, 4096, [])
        blob = mask.to_bytes()
        assert blob == b""

        restored = DecoderBitmask.from_bytes(0, 4096, blob)
        assert restored.num_frozen() == 0

    def test_full_bitmask(self):
        """Test fully frozen layer."""
        full = EncoderBitmask(0, 100, list(range(100)))
        assert full.pct_frozen() == 100.0
        assert full.num_frozen() == 100

        blob = full.to_bytes()
        restored = DecoderBitmask.from_bytes(0, 100, blob)
        assert restored.pct_frozen() == 100.0

    def test_bitmask_boundary_conditions(self):
        """Test edge cases."""
        # Single neuron
        mask1 = EncoderBitmask(0, 1, [0])
        assert mask1.num_frozen() == 1
        assert mask1.pct_frozen() == 100.0

        # Large layer
        large = list(range(0, 100000, 100))
        mask2 = EncoderBitmask(0, 100000, large)
        assert mask2.num_frozen() == len(large)

        # Out-of-bounds indices (should be ignored)
        mask3 = EncoderBitmask(0, 100, [50, 150, 200])
        blob = mask3.to_bytes()
        restored = DecoderBitmask.from_bytes(0, 100, blob)
        assert restored.num_frozen() == 1  # Only idx 50


class TestDetectionMethods:
    """Test saturation detection algorithms (torch-dependent)."""

    def test_variance_gradient_detection(self):
        """Test variance+gradient detection method."""
        if not HAS_TORCH:
            print("  (Skipped: torch unavailable)")
            return

        # Create test activations: some frozen neurons, some active
        seq_len, hidden_dim = 128, 4096
        acts = torch.randn(seq_len, hidden_dim)

        # Freeze some neurons (near-zero, low variance)
        acts[:, :256] *= 0.001  # Very low magnitude

        frozen = _detect_frozen_variance_gradient(acts, quantile=0.2)
        assert len(frozen) > 0
        assert len(frozen) < 4096

        # Should detect most of the low-magnitude neurons
        assert sum(1 for i in frozen if i < 256) > 100

    def test_activity_counting_detection(self):
        """Test activity counting detection."""
        if not HAS_TORCH:
            print("  (Skipped: torch unavailable)")
            return

        seq_len, hidden_dim = 128, 4096
        acts = torch.randn(seq_len, hidden_dim)

        # Make some neurons mostly zero
        acts[:100, :128] = 0.0001

        frozen = _detect_frozen_activity(acts, threshold=0.001)
        assert len(frozen) > 0

        # Should detect the frozen neurons
        assert sum(1 for i in frozen if i < 128) > 50

    def test_statistical_detection(self):
        """Test statistical quantile detection."""
        if not HAS_TORCH:
            print("  (Skipped: torch unavailable)")
            return

        seq_len, hidden_dim = 128, 4096
        acts = torch.randn(seq_len, hidden_dim)

        frozen = _detect_frozen_statistical(acts, quantile=0.2)
        assert len(frozen) > 0

        # With quantile=0.2, should freeze ~20% of neurons
        assert len(frozen) / hidden_dim >= 0.15
        assert len(frozen) / hidden_dim <= 0.25

    def test_cliff_score_computation(self):
        """Test cliff score for early saturation."""
        if not HAS_TORCH:
            print("  (Skipped: torch unavailable)")
            return

        seq_len, hidden_dim = 512, 2048
        acts = torch.randn(seq_len, hidden_dim)

        frozen_indices = list(range(0, 256))
        cliff_score = _compute_cliff_score(acts, frozen_indices)

        assert 0.0 <= cliff_score <= 1.0
        assert isinstance(cliff_score, float)


class TestSaturationMasks:
    """Test SaturationMasks container."""

    def test_masks_creation_and_serialization(self):
        """Test mask container creation and byte serialization."""
        masks = SaturationMasks(
            model_name="test-model",
            num_layers=12,
            method="variance_gradient",
            created_at=time.time(),
            ffn_masks={
                0: EncoderBitmask(0, 3072, list(range(0, 100))),
                5: EncoderBitmask(5, 3072, list(range(100, 200))),
                11: EncoderBitmask(11, 3072, list(range(200, 300))),
            },
            cliff_scores={0: 0.5, 5: 0.3, 11: 0.2},
            metadata={"source": "test"},
        )

        # Serialize
        blob = masks.masks_to_bytes()
        assert len(blob) > 0

        # Deserialize
        restored = SaturationMasks.masks_from_bytes(blob, 12)
        assert len(restored) == 3
        assert restored[0].num_frozen() == 100
        assert restored[5].num_frozen() == 100
        assert restored[11].num_frozen() == 100

    def test_masks_to_dict(self):
        """Test serialization to dict."""
        masks = SaturationMasks(
            model_name="test",
            num_layers=8,
            method="activity_counting",
            created_at=12345.0,
            ffn_masks={0: EncoderBitmask(0, 4096, list(range(500)))},
            cliff_scores={0: 0.7},
            metadata={},
        )

        data = masks.to_dict()
        assert data["model_name"] == "test"
        assert data["num_layers"] == 8
        assert data["method"] == "activity_counting"
        assert "summary" in data


class TestSafeTensorsIntegration:
    """Test SafeTensors encoding/decoding."""

    def test_safetensors_roundtrip(self):
        """Test encoding and decoding with SafeTensors."""
        if not HAS_TORCH:
            print("  (Skipped: torch unavailable)")
            return

        try:
            from saturation_mask_encoder import encode_masks_to_safetensors
        except ImportError:
            print("  (Skipped: SafeTensors test)")
            return

        # Create test masks
        masks = SaturationMasks(
            model_name="phi3-mini",
            num_layers=32,
            method="variance_gradient",
            created_at=time.time(),
            ffn_masks={i: EncoderBitmask(i, 8192, list(range(i*10, i*10+50)))
                      for i in range(5)},
            cliff_scores={i: 0.5 - i*0.1 for i in range(5)},
            metadata={"source": "test", "version": "1.0"},
        )

        with tempfile.TemporaryDirectory() as tmpdir:
            output_path = Path(tmpdir) / "test_model.safetensors"

            # Create dummy SafeTensors file
            dummy_tensors = {
                "model.embed_tokens.weight": torch.randn(32064, 3072),
            }
            from safetensors.torch import save_file
            save_file(dummy_tensors, str(output_path))

            # Encode masks
            encode_masks_to_safetensors(str(output_path), masks, str(output_path))

            # Decode masks
            from saturation_mask_decoder import load_saturation_masks
            restored_masks = load_saturation_masks(str(output_path))

            if restored_masks:
                assert len(restored_masks) == len(masks.ffn_masks)
                for layer_id in masks.ffn_masks:
                    assert layer_id in restored_masks


class TestBenchmark:
    """Benchmark mask computation and serialization."""

    def test_bitmask_serialization_performance(self):
        """Benchmark bitmask serialization."""
        print("\n=== BITMASK SERIALIZATION BENCHMARK ===")

        sizes = [1024, 4096, 8192, 16384]
        frozen_pcts = [0.1, 0.5, 1.0]

        for size in sizes:
            for pct in frozen_pcts:
                num_frozen = int(size * pct / 100)
                frozen_indices = list(range(0, num_frozen))

                mask = EncoderBitmask(0, size, frozen_indices)

                # Time serialization
                start = time.time()
                for _ in range(1000):
                    blob = mask.to_bytes()
                elapsed = time.time() - start

                size_bytes = len(blob)
                throughput = 1000 / elapsed

                print(f"Size={size:5d}, Frozen={pct:.1f}%, "
                      f"Blob={size_bytes:6d}B, {throughput:.0f} ops/sec")

    def test_cliff_score_performance(self):
        """Benchmark cliff score computation (torch-dependent)."""
        if not HAS_TORCH:
            print("  (Skipped: torch unavailable)")
            return

        print("\n=== CLIFF SCORE COMPUTATION BENCHMARK ===")

        seq_lens = [128, 512, 2048]
        hidden_dims = [3072, 4096, 8192]

        for seq_len in seq_lens:
            for hidden_dim in hidden_dims:
                acts = torch.randn(seq_len, hidden_dim)
                frozen_indices = list(range(0, hidden_dim // 10))

                start = time.time()
                for _ in range(100):
                    score = _compute_cliff_score(acts, frozen_indices)
                elapsed = time.time() - start

                time_per_op = elapsed / 100 * 1000

                print(f"Seq={seq_len:4d}, Dim={hidden_dim:5d}: "
                      f"{time_per_op:.2f} ms/op")

    def test_deserialization_performance(self):
        """Benchmark mask deserialization."""
        print("\n=== DESERIALIZATION BENCHMARK ===")

        # Create realistic mask blob (32 layers, ~10% frozen each)
        all_masks = {
            i: EncoderBitmask(i, 8192, list(range(0, 800)))
            for i in range(32)
        }

        masks = SaturationMasks(
            model_name="test",
            num_layers=32,
            method="variance_gradient",
            created_at=time.time(),
            ffn_masks=all_masks,
            cliff_scores={i: 0.5 for i in range(32)},
            metadata={},
        )

        blob = masks.masks_to_bytes()

        print(f"Blob size: {len(blob) / 1024:.2f} KB")

        # Deserialize 1000 times
        start = time.time()
        for _ in range(1000):
            restored = _deserialize_masks_blob(blob)
        elapsed = time.time() - start

        time_per_op = elapsed / 1000 * 1000000  # microseconds

        print(f"Deserialization: {time_per_op:.2f} µs/op")
        print(f"Per-model load: {time_per_op * 32 / 1000:.2f} ms (32 layers)")


def run_tests():
    """Run all test suites."""
    test_classes = [
        TestBitmask,
        TestDetectionMethods,
        TestSaturationMasks,
        TestSafeTensorsIntegration,
        TestBenchmark,
    ]

    total_passed = 0
    total_failed = 0

    for test_class in test_classes:
        print(f"\n{'='*60}")
        print(f"Running {test_class.__name__}")
        print('='*60)

        instance = test_class()
        for method_name in dir(instance):
            if method_name.startswith("test_"):
                try:
                    method = getattr(instance, method_name)
                    method()
                    print(f"✓ {method_name}")
                    total_passed += 1
                except AssertionError as e:
                    print(f"✗ {method_name}: {e}")
                    total_failed += 1
                except Exception as e:
                    print(f"✗ {method_name}: {type(e).__name__}: {e}")
                    total_failed += 1

    print(f"\n{'='*60}")
    print(f"RESULTS: {total_passed} passed, {total_failed} failed")
    print('='*60)

    return total_failed == 0


if __name__ == "__main__":
    success = run_tests()
    sys.exit(0 if success else 1)
